sql:
SELECT EXISTS(
    SELECT 1
    FROM registrations
    WHERE session_id = 1 AND is_active = 1
) as has_active_registration;

SELECT COUNT(*) 
FROM sessions 
WHERE session_id NOT IN (SELECT session_id FROM waitlists);

SELECT 
  (SELECT COUNT(*) FROM users WHERE is_active = 1) AS total_active_users,
  (SELECT COUNT(*) FROM feedback) AS total_feedback_count;

SELECT COUNT(DISTINCT participant_name)
FROM registrations
WHERE session_id = 1;
